REFRESH_TOKEN_EXPIRE_DAYS = 30
REFRESH_SECRET_KEY = "different-secret-for-refresh-tokens"

def create_refresh_token(user_id: str) -> str:
    expire = datetime.now(timezone.utc) + timedelta(days=REFRESH_TOKEN_EXPIRE_DAYS)
    return jwt.encode(
        {"sub": user_id, "exp": expire, "type": "refresh"},
        REFRESH_SECRET_KEY,
        algorithm=ALGORITHM
    )

@app.post("/auth/token")
async def login(
    form_data: OAuth2PasswordRequestForm = Depends(),
    response: Response = None
):
    user = await authenticate_user(form_data.username, form_data.password)

    access_token = create_access_token({"sub": user.user_id})
    refresh_token = create_refresh_token(user.user_id)

    # Store refresh token reference in DB for revocation support
    await store_refresh_token(user.user_id, refresh_token)

    # Refresh token in httpOnly cookie — not accessible to JavaScript
    response.set_cookie(
        key="refresh_token",
        value=refresh_token,
        httponly=True,
        secure=True,
        samesite="strict",
        max_age=REFRESH_TOKEN_EXPIRE_DAYS * 86400
    )

    return {"access_token": access_token, "token_type": "bearer"}

@app.post("/auth/refresh")
async def refresh_access_token(refresh_token: str = Cookie(...)):
    try:
        payload = jwt.decode(refresh_token, REFRESH_SECRET_KEY, algorithms=[ALGORITHM])
        if payload.get("type") != "refresh":
            raise HTTPException(status_code=401, detail="Invalid token type")
        user_id = payload["sub"]
    except JWTError:
        raise HTTPException(status_code=401, detail="Invalid refresh token")

    # Check if token has been revoked
    if not await is_refresh_token_valid(user_id, refresh_token):
        raise HTTPException(status_code=401, detail="Refresh token revoked")

    new_access_token = create_access_token({"sub": user_id})
    return {"access_token": new_access_token, "token_type": "bearer"}

@app.post("/auth/logout")
async def logout(
    refresh_token: str = Cookie(default=None),
    response: Response = None,
    current_user: UserInDB = Depends(get_current_user)
):
    if refresh_token:
        await revoke_refresh_token(current_user.user_id, refresh_token)
    response.delete_cookie("refresh_token")
    return {"message": "Logged out"}

import time
from collections import defaultdict
from fastapi import Request, HTTPException

class RateLimiter:
    def __init__(self, max_requests: int, window_seconds: int):
        self.max_requests = max_requests
        self.window = window_seconds
        self.requests: dict = defaultdict(list)

    def is_allowed(self, key: str) -> bool:
        now = time.time()
        window_start = now - self.window
        self.requests[key] = [t for t in self.requests[key] if t > window_start]
        if len(self.requests[key]) >= self.max_requests:
            return False
        self.requests[key].append(now)
        return True

rate_limiter = RateLimiter(max_requests=100, window_seconds=60)

@app.middleware("http")
async def rate_limit_middleware(request: Request, call_next):
    client_ip = request.client.host
    if not rate_limiter.is_allowed(client_ip):
        raise HTTPException(
            status_code=429,
            detail="Rate limit exceeded",
            headers={"Retry-After": "60"}
        )
    return await call_next(request)

