from fastapi import FastAPI, Depends, HTTPException, Header, Security, status
from fastapi.security import OAuth2PasswordBearer
from pydantic import BaseModel
from typing import Optional, List
from jose import jwt, JWTError

app = FastAPI()
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="/auth/token", auto_error=False)

class AuthContext(BaseModel):
    user_id: str
    tenant_id: str
    roles: List[str]
    auth_method: str   # "jwt" or "api_key"

    class Config:
        frozen = True

async def resolve_auth_context(
    token: Optional[str] = Depends(oauth2_scheme),
    x_api_key: Optional[str] = Header(default=None),
) -> AuthContext:
    # Try JWT first
    if token:
        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
            return AuthContext(
                user_id=payload["sub"],
                tenant_id=payload["tenant_id"],
                roles=payload.get("roles", []),
                auth_method="jwt"
            )
        except JWTError:
            raise HTTPException(status_code=401, detail="Invalid token")

    # Fall back to API key
    if x_api_key:
        key_record = await lookup_api_key(x_api_key)
        if not key_record:
            raise HTTPException(status_code=403, detail="Invalid API key")
        return AuthContext(
            user_id=key_record.service_account_id,
            tenant_id=key_record.tenant_id,
            roles=key_record.scopes,
            auth_method="api_key"
        )

    raise HTTPException(status_code=401, detail="Authentication required")

def require_tenant_access(resource_tenant_id: str, ctx: AuthContext):
    """Enforce tenant isolation — no user can access another tenant's data."""
    if ctx.tenant_id != resource_tenant_id:
        raise HTTPException(status_code=404, detail="Resource not found")  # 404, not 403

def require_role(role: str):
    def checker(ctx: AuthContext = Depends(resolve_auth_context)) -> AuthContext:
        if role not in ctx.roles:
            raise HTTPException(status_code=403, detail=f"Role '{role}' required")
        return ctx
    return checker

@app.get("/tenants/{tenant_id}/reports")
async def get_reports(
    tenant_id: str,
    ctx: AuthContext = Depends(resolve_auth_context)
):
    require_tenant_access(tenant_id, ctx)

    if "reports:read" not in ctx.roles and "admin" not in ctx.roles:
        raise HTTPException(status_code=403, detail="Insufficient permissions")

    return await fetch_reports(tenant_id)

